// Generated by forge proof from db-pipelines.md
import { describe, test, expect, beforeEach } from 'bun:test';
import type { Database } from 'bun:sqlite';
import { getTestDb } from './db.js';
import { SqliteStateProvider } from './db-pipeline-state.js';
import { STAGE_ORDER, DEFAULT_GATES } from './pipeline-types.js';
import type { Pipeline, PipelineOptions, GateKey } from './pipeline-types.js';

// ── Helpers ──────────────────────────────────────────────────

function makePipelineOptions(overrides: Partial<PipelineOptions> = {}): PipelineOptions {
  return {
    goal: 'Build authentication system',
    ...overrides,
  };
}

// ── SqliteStateProvider: createPipeline ───────────────────────

describe('SqliteStateProvider.createPipeline', () => {
  let db: Database;
  let provider: SqliteStateProvider;

  beforeEach(() => {
    db = getTestDb();
    provider = new SqliteStateProvider(db);
  });

  test('returns a Pipeline with correct goal and pending status', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions({ goal: 'Test goal' }));
    expect(pipeline.goal).toBe('Test goal');
    expect(pipeline.status).toBe('pending');
  });

  test('assigns a non-empty id', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    expect(pipeline.id).toBeTruthy();
    expect(typeof pipeline.id).toBe('string');
  });

  test('creates all 5 stages in canonical order', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    expect(pipeline.stages.length).toBe(STAGE_ORDER.length);
    for (let i = 0; i < STAGE_ORDER.length; i++) {
      expect(pipeline.stages[i].name).toBe(STAGE_ORDER[i]);
    }
  });

  test('all stages start as pending', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    for (const stage of pipeline.stages) {
      expect(stage.status).toBe('pending');
    }
  });

  test('creates all 4 gates with default types', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const gateKeys: GateKey[] = ['define -> run', 'run -> audit', 'audit -> proof', 'proof -> verify'];
    for (const key of gateKeys) {
      const gate = pipeline.gates[key];
      expect(gate).toBeDefined();
      expect(gate.type).toBe(DEFAULT_GATES[key]);
      expect(gate.status).toBe('waiting');
    }
  });

  test('respects gate overrides', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions({
      gates: { 'define -> run': 'confirm', 'proof -> verify': 'review' },
    }));
    expect(pipeline.gates['define -> run'].type).toBe('confirm');
    expect(pipeline.gates['proof -> verify'].type).toBe('review');
    expect(pipeline.gates['run -> audit'].type).toBe(DEFAULT_GATES['run -> audit']);
  });

  test('sets createdAt and updatedAt timestamps', async () => {
    const before = new Date().toISOString();
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const after = new Date().toISOString();

    expect(pipeline.createdAt >= before).toBe(true);
    expect(pipeline.createdAt <= after).toBe(true);
    expect(pipeline.updatedAt >= before).toBe(true);
  });

  test('persists to database (row found in DB)', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const row = db.query('SELECT id, goal, status FROM pipelines WHERE id = ?').get(pipeline.id) as {
      id: string; goal: string; status: string;
    } | null;
    expect(row).not.toBeNull();
    expect(row!.goal).toBe('Build authentication system');
    expect(row!.status).toBe('pending');
  });

  test('persists all stage rows to DB', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const rows = db.query('SELECT name FROM stages WHERE pipeline_id = ?').all(pipeline.id) as Array<{ name: string }>;
    expect(rows.length).toBe(STAGE_ORDER.length);
  });

  test('persists all gate rows to DB', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const rows = db.query('SELECT from_stage, to_stage FROM gates WHERE pipeline_id = ?').all(pipeline.id) as Array<{ from_stage: string; to_stage: string }>;
    expect(rows.length).toBe(4);
  });

  test('fromStage marks earlier stages as skipped', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions({ fromStage: 'audit' }));
    const defineStage = pipeline.stages.find(s => s.name === 'define');
    const runStage = pipeline.stages.find(s => s.name === 'run');
    const auditStage = pipeline.stages.find(s => s.name === 'audit');

    expect(defineStage!.status).toBe('skipped');
    expect(runStage!.status).toBe('skipped');
    expect(auditStage!.status).toBe('pending');
  });
});

// ── SqliteStateProvider.loadPipeline ─────────────────────────

describe('SqliteStateProvider.loadPipeline', () => {
  let db: Database;
  let provider: SqliteStateProvider;

  beforeEach(() => {
    db = getTestDb();
    provider = new SqliteStateProvider(db);
  });

  test('returns null for unknown pipeline id', async () => {
    const result = await provider.loadPipeline('nonexistent-id');
    expect(result).toBeNull();
  });

  test('loads a previously created pipeline', async () => {
    const created = await provider.createPipeline(makePipelineOptions({ goal: 'Load test' }));
    const loaded = await provider.loadPipeline(created.id);

    expect(loaded).not.toBeNull();
    expect(loaded!.id).toBe(created.id);
    expect(loaded!.goal).toBe('Load test');
    expect(loaded!.status).toBe('pending');
  });

  test('loaded pipeline has all stages in canonical order', async () => {
    const created = await provider.createPipeline(makePipelineOptions());
    const loaded = await provider.loadPipeline(created.id);

    expect(loaded!.stages.length).toBe(STAGE_ORDER.length);
    for (let i = 0; i < STAGE_ORDER.length; i++) {
      expect(loaded!.stages[i].name).toBe(STAGE_ORDER[i]);
    }
  });

  test('loaded pipeline has all gates', async () => {
    const created = await provider.createPipeline(makePipelineOptions());
    const loaded = await provider.loadPipeline(created.id);

    const gateKeys: GateKey[] = ['define -> run', 'run -> audit', 'audit -> proof', 'proof -> verify'];
    for (const key of gateKeys) {
      expect(loaded!.gates[key]).toBeDefined();
    }
  });
});

// ── SqliteStateProvider.savePipeline ─────────────────────────

describe('SqliteStateProvider.savePipeline', () => {
  let db: Database;
  let provider: SqliteStateProvider;

  beforeEach(() => {
    db = getTestDb();
    provider = new SqliteStateProvider(db);
  });

  test('updates pipeline status', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    pipeline.status = 'running';
    await provider.savePipeline(pipeline);

    const loaded = await provider.loadPipeline(pipeline.id);
    expect(loaded!.status).toBe('running');
  });

  test('updates stage status and cost', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const defineStage = pipeline.stages.find(s => s.name === 'define')!;
    defineStage.status = 'completed';
    defineStage.cost = 0.50;
    defineStage.completedAt = new Date().toISOString();
    await provider.savePipeline(pipeline);

    const loaded = await provider.loadPipeline(pipeline.id);
    const loadedDefine = loaded!.stages.find(s => s.name === 'define')!;
    expect(loadedDefine.status).toBe('completed');
    expect(loadedDefine.cost).toBe(0.50);
  });

  test('updates gate status to approved', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const approvedAt = new Date().toISOString();
    pipeline.gates['define -> run'].status = 'approved';
    pipeline.gates['define -> run'].approvedAt = approvedAt;
    await provider.savePipeline(pipeline);

    const loaded = await provider.loadPipeline(pipeline.id);
    expect(loaded!.gates['define -> run'].status).toBe('approved');
    expect(loaded!.gates['define -> run'].approvedAt).toBe(approvedAt);
  });

  test('updates totalCost', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    pipeline.totalCost = 2.50;
    await provider.savePipeline(pipeline);

    const loaded = await provider.loadPipeline(pipeline.id);
    expect(loaded!.totalCost).toBe(2.50);
  });

  test('updates completedAt when set', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    pipeline.status = 'completed';
    pipeline.completedAt = new Date().toISOString();
    await provider.savePipeline(pipeline);

    const loaded = await provider.loadPipeline(pipeline.id);
    expect(loaded!.completedAt).toBeTruthy();
  });

  test('persists session IDs in stage sessions array', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const defineStage = pipeline.stages.find(s => s.name === 'define')!;
    defineStage.sessions = ['sess-001', 'sess-002'];
    await provider.savePipeline(pipeline);

    const loaded = await provider.loadPipeline(pipeline.id);
    const loadedDefine = loaded!.stages.find(s => s.name === 'define')!;
    expect(loadedDefine.sessions).toEqual(['sess-001', 'sess-002']);
  });

  test('persists artifacts in stage', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    const runStage = pipeline.stages.find(s => s.name === 'run')!;
    runStage.artifacts = { specDir: 'specs/auth/', resultsDir: '.forge/results/' };
    await provider.savePipeline(pipeline);

    const loaded = await provider.loadPipeline(pipeline.id);
    const loadedRun = loaded!.stages.find(s => s.name === 'run')!;
    expect(loadedRun.artifacts).toEqual({ specDir: 'specs/auth/', resultsDir: '.forge/results/' });
  });
});

// ── SqliteStateProvider.loadActivePipeline ────────────────────

describe('SqliteStateProvider.loadActivePipeline', () => {
  let db: Database;
  let provider: SqliteStateProvider;

  beforeEach(() => {
    db = getTestDb();
    provider = new SqliteStateProvider(db);
  });

  test('returns null when no pipelines exist', async () => {
    const result = await provider.loadActivePipeline();
    expect(result).toBeNull();
  });

  test('returns null when all pipelines are in terminal state', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    pipeline.status = 'completed';
    pipeline.completedAt = new Date().toISOString();
    await provider.savePipeline(pipeline);

    const result = await provider.loadActivePipeline();
    expect(result).toBeNull();
  });

  test('returns the most recently updated active pipeline', async () => {
    const p1 = await provider.createPipeline(makePipelineOptions({ goal: 'First' }));
    await new Promise(r => setTimeout(r, 5)); // ensure unique IDs via Date.now()
    const p2 = await provider.createPipeline(makePipelineOptions({ goal: 'Second (newer)' }));

    // Force specific updated_at values so ordering is deterministic
    db.run("UPDATE pipelines SET updated_at = '2026-01-01T12:00:00Z' WHERE id = ?", [p1.id]);
    db.run("UPDATE pipelines SET updated_at = '2026-01-01T13:00:00Z' WHERE id = ?", [p2.id]);

    const result = await provider.loadActivePipeline();
    expect(result).not.toBeNull();
    expect(result!.goal).toBe('Second (newer)');
  });

  test('returns running pipeline', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions({ goal: 'Running pipeline' }));
    pipeline.status = 'running';
    await provider.savePipeline(pipeline);

    const result = await provider.loadActivePipeline();
    expect(result).not.toBeNull();
    expect(result!.status).toBe('running');
  });

  test('returns paused_at_gate pipeline', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions({ goal: 'Paused pipeline' }));
    pipeline.status = 'paused_at_gate';
    await provider.savePipeline(pipeline);

    const result = await provider.loadActivePipeline();
    expect(result).not.toBeNull();
    expect(result!.status).toBe('paused_at_gate');
  });

  test('does not return failed pipeline', async () => {
    const pipeline = await provider.createPipeline(makePipelineOptions());
    pipeline.status = 'failed';
    await provider.savePipeline(pipeline);

    const result = await provider.loadActivePipeline();
    expect(result).toBeNull();
  });
});

// ── SqliteStateProvider.listPipelines ────────────────────────

describe('SqliteStateProvider.listPipelines', () => {
  let db: Database;
  let provider: SqliteStateProvider;

  beforeEach(() => {
    db = getTestDb();
    provider = new SqliteStateProvider(db);
  });

  test('returns empty array when no pipelines', async () => {
    const result = await provider.listPipelines();
    expect(result).toEqual([]);
  });

  test('returns all pipelines ordered by created_at DESC', async () => {
    const p1 = await provider.createPipeline(makePipelineOptions({ goal: 'First' }));
    await new Promise(r => setTimeout(r, 5));
    const p2 = await provider.createPipeline(makePipelineOptions({ goal: 'Second' }));
    await new Promise(r => setTimeout(r, 5));
    const p3 = await provider.createPipeline(makePipelineOptions({ goal: 'Third' }));

    db.run("UPDATE pipelines SET created_at = '2026-01-01T10:00:00Z' WHERE id = ?", [p1.id]);
    db.run("UPDATE pipelines SET created_at = '2026-01-01T12:00:00Z' WHERE id = ?", [p2.id]);
    db.run("UPDATE pipelines SET created_at = '2026-01-01T11:00:00Z' WHERE id = ?", [p3.id]);

    const result = await provider.listPipelines();
    expect(result.length).toBe(3);
    expect(result[0].goal).toBe('Second'); // newest
    expect(result[1].goal).toBe('Third');
    expect(result[2].goal).toBe('First'); // oldest
  });

  test('includes pipelines in all statuses', async () => {
    const p1 = await provider.createPipeline(makePipelineOptions({ goal: 'Pending' }));
    await new Promise(r => setTimeout(r, 5));
    const p2 = await provider.createPipeline(makePipelineOptions({ goal: 'Completed' }));
    p2.status = 'completed';
    p2.completedAt = new Date().toISOString();
    await provider.savePipeline(p2);
    await new Promise(r => setTimeout(r, 5));
    const p3 = await provider.createPipeline(makePipelineOptions({ goal: 'Failed' }));
    p3.status = 'failed';
    await provider.savePipeline(p3);

    const result = await provider.listPipelines();
    expect(result.length).toBe(3);
    const statuses = result.map(p => p.status);
    expect(statuses).toContain('pending');
    expect(statuses).toContain('completed');
    expect(statuses).toContain('failed');
  });
});

